var body = $json.body || $json;
var requirement = body.requirement || {};
var proposalAnalysis = body.proposalAnalysis || {};
var proposalText = (body.proposalText || '').substring(0, 50000);
var reqStr = JSON.stringify(requirement, null, 2).substring(0, 5000);
var analysisStr = JSON.stringify(proposalAnalysis, null, 2).substring(0, 25000);

var p = 'Ти си член на оценителна комисия по обществена поръчка. Изготвяш КОНСТАТАЦИЯ за ЕДНО КОНКРЕТНО изискване — в структурата на реален протокол за отстраняване от процедура.

';
p += '## ИЗИСКВАНЕ ЗА ПРОВЕРКА:
' + reqStr + '

';
p += '## СТРУКТУРИРАН АНАЛИЗ НА ПРЕДЛОЖЕНИЕТО (включва вътрешни противоречия, липси, агрегирани данни):
' + analysisStr + '

';
p += '## СУРОВ ТЕКСТ НА ТЕХНИЧЕСКОТО ПРЕДЛОЖЕНИЕ:
' + proposalText + '

';
p += '## СТРУКТУРА НА КОНСТАТАЦИЯТА — СЛЕДВАЙ ТАЗИ ТОЧНА ПОСЛЕДОВАТЕЛНОСТ:

';
p += '### СТЪПКА 1: Изискване на възложителя (ДОСЛОВНО)
';
p += 'Цитирай ДОСЛОВНО текста на изискването от документацията. Започни с: "Съгласно [секция] от документацията, участникът е длъжен да представи/опише/включи..."

';
p += '### СТЪПКА 2: Какво се очаква от участника
';
p += 'Опиши КОНКРЕТНО какво ТРЯБВА да съдържа техническото предложение за покриване на ТОВА изискване. Бъди ДЕТАЙЛЕН — включи ВСЯКА подточка от изискването.

';
p += '### СТЪПКА 3: Какво РЕАЛНО е представил участникът
';
p += 'Опиши с ДОСЛОВНИ ЦИТАТИ какво е написал участникът по това изискване. Ако не е адресирано — кажи ясно. Ако е адресирано частично — посочи КОГА (секция/страница) и КАКВО точно е написал.

';
p += '### СТЪПКА 4: Конкретни несъответствия и дефицити
';
p += 'Това е НАЙ-ВАЖНАТА стъпка. Описвай КОНКРЕТНИ проблеми в следния формат:

';
p += '**За числови противоречия:**
';
p += '"В работната програма (стр. X) за дейност [име] участникът е посочил [Y] работника, докато в линейния график (стр. Z) за същата дейност са предвидени [W] работника. Налице е противоречие между двете части на техническото предложение."

';
p += '**За липсващи елементи:**
';
p += '"Изискването предвижда описание на [X] за ВСЯКА позиция от КСС. Участникът е описал [X] само за позиции [1, 3, 5], без да адресира позиции [2, 4, 6, 7]. Липсва описание за [N] от общо [M] позиции."

';
p += '**За агрегирани данни:**
';
p += '"В линейния график позиции [1-8] от КСС са обединени в една обща дейност "[Име]" без индивидуална разбивка на продължителността на всяка отделна позиция. Документацията изисква линейният график да показва ВСЯКА дейност поотделно."

';
p += '**За generic/шаблонен текст:**
';
p += '"Участникът описва [цитат], което е обща формулировка, приложима за всяка поръчка, без конкретна връзка с предмета на настоящата процедура."

';
p += '**За липса на разпределение:**
';
p += '"Не е представено разпределение на отговорностите по ВИДОВЕ строителни дейности — участникът е описал само обща организационна структура без връзка с конкретните дейности от КСС."

';
p += '### СТЪПКА 5: Извод
';
p += 'Формулирай ПРАВЕН извод:
';
p += '- Ако има съществено несъответствие: "Посочените обстоятелства обосновават извод за несъответствие на техническото предложение с изискването на [секция] от документацията."
';
p += '- Ако е частично: "Техническото предложение частично покрива изискването, но са налице конкретни непълноти по отношение на [какво]."
';
p += '- Ако съответства: "Техническото предложение съответства на изискването."

';
p += '## СТАТУСИ:
';
p += '- COMPLIANT: Покрива ИЗЦЯЛО изискването с всички подточки
';
p += '- PARTIALLY_COMPLIANT: Адресирано, но с конкретни непълноти или противоречия
';
p += '- NON_COMPLIANT: Съществено несъответствие — липсващи задължителни елементи или вътрешни противоречия
';
p += '- MISSING: Изобщо НЕ е адресирано в предложението

';
p += '## КРИТИЧНИ ПРАВИЛА:
';
p += '- Използвай ДОСЛОВНИ ЦИТАТИ от предложението — с посочване на секция/страница
';
p += '- Давай КОНКРЕТНИ числа — "3 работника" вместо "недостатъчен брой"
';
p += '- Посочвай КОНКРЕТНИ позиции — "позиции 4, 7 и 12 от КСС" вместо "някои позиции"
';
p += '- НЕ СЕ ПРОИЗНАСЯЙ по неща извън ТОВА КОНКРЕТНО изискване
';
p += '- НЕ измисляй проблеми — ако няма несъответствие, кажи COMPLIANT
';
p += '- Бъди ОБЕКТИВЕН — отчитай и добре покритите аспекти

';
p += '## ФОРМАТ НА ОТГОВОР
';
p += 'Върни САМО валиден JSON (без markdown блокове):
';
p += '{
';
p += '  "requirement_id": "R1",
';
p += '  "requirement_title": "заглавие",
';
p += '  "status": "COMPLIANT|PARTIALLY_COMPLIANT|NON_COMPLIANT|MISSING",
';
p += '  "requirement_verbatim": "ДОСЛОВЕН текст на изискването от документацията",
';
p += '  "expected_content": "Какво КОНКРЕТНО трябва да съдържа ТП за това изискване",
';
p += '  "actual_content": "Какво РЕАЛНО е представил участникът — с дословни цитати и позовавания",
';
p += '  "deficiencies": [
';
p += '    {
';
p += '      "type": "contradiction|missing_element|aggregated_data|generic_text|incomplete_coverage",
';
p += '      "description": "КОНКРЕТНО описание на проблема със СПЕЦИФИЧНИ числа, страници, позиции",
';
p += '      "evidence_location_1": "Къде в ТП е първото твърдение (секция/страница)",
';
p += '      "evidence_value_1": "Конкретна стойност на първата страна на противоречието",
';
p += '      "evidence_location_2": "Къде в ТП е второто противоречащо твърдение (ако е приложимо)",
';
p += '      "evidence_value_2": "Конкретна стойност на втората страна",
';
p += '      "severity": "CRITICAL|MAJOR|MINOR"
';
p += '    }
';
p += '  ],
';
p += '  "sub_requirement_coverage": [
';
p += '    {
';
p += '      "sub_req_id": "R1.1",
';
p += '      "sub_req_text": "текст на подизискването",
';
p += '      "covered": true,
';
p += '      "notes": "конкретни бележки"
';
p += '    }
';
p += '  ],
';
p += '  "legal_conclusion": "Формален правен извод — 1-2 изречения в стил на протокол за отстраняване",
';
p += '  "notes": "Допълнителни бележки"
';
p += '}';

return [{ json: { prompt: p } }];

var raw = ($json.text || $json.response || '').trim();
var result;

try {
  result = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  var candidate = m ? m[1].trim() : raw;
  try {
    var s = candidate.indexOf('{');
    var e2 = candidate.lastIndexOf('}');
    var js = candidate.substring(s, e2 + 1).replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(js);
  } catch (e3) {
    result = {
      requirement_id: 'UNKNOWN',
      status: 'COMPLIANT',
      analysis: 'Parse error — defaulting to COMPLIANT to avoid false positives',
      deficiencies: [],
      score: 70,
      _parse_error: true
    };
  }
}

// Validate status
var validStatuses = ['COMPLIANT', 'PARTIALLY_COMPLIANT', 'NON_COMPLIANT', 'MISSING'];
if (validStatuses.indexOf(result.status) === -1) {
  result.status = result.score >= 80 ? 'COMPLIANT' : 'PARTIALLY_COMPLIANT';
}

return [{ json: { finding: result } }];
